const db = require('../../models');
const { NotFoundError, BadParameters, ForbiddenError } = require('../../utils/coreErrors');
const { isSendOnlyChannel } = require('./externalIntegration.getContactProfile');
const { CONTACT_VARIABLE, LINK_CODE_CACHE_PREFIX } = require('./constants');

/**
 * @description Link an external contact to a Gladys user, on behalf of the
 * integration (POST /contact/link): the code generated by the user in the
 * Gladys UI proves the consent. Single use: the code dies here, valid or
 * expired. The link is stored in a variable scoped (service_id, user_id) —
 * the nextcloud-talk pattern, no migration.
 * @param {object} service - The external integration service (plain object).
 * @param {object} body - The link request.
 * @param {string} body.code - The short code generated by the user.
 * @param {string} body.contact_id - Id of the contact in the external channel.
 * @param {string} [body.contact_name] - Display name of the contact.
 * @returns {Promise<object>} Resolve with { user: { selector, first_name, language } }.
 * @example
 * await gladys.externalIntegration.linkContact(service, { code: 'AB23CD45', contact_id: '12345' });
 */
async function linkContact(service, { code, contact_id: contactId, contact_name: contactName } = {}) {
  // mirror of createLinkCode: no code-based link on a send-only channel
  if (isSendOnlyChannel(service.manifest)) {
    throw new ForbiddenError('LINK_CODE_NOT_AVAILABLE');
  }
  if (typeof code !== 'string' || code.length === 0) {
    throw new BadParameters('code: must be a non-empty string');
  }
  if (typeof contactId !== 'string' || contactId.length === 0) {
    throw new BadParameters('contact_id: must be a non-empty string');
  }
  if (contactName !== undefined && typeof contactName !== 'string') {
    throw new BadParameters('contact_name: must be a string');
  }
  const cacheKey = `${LINK_CODE_CACHE_PREFIX}:${service.id}:${code.toUpperCase()}`;
  const entry = this.cache.get(cacheKey);
  // single use: consumed on any attempt, and expiry is checked here (the
  // in-memory cache has no TTL of its own)
  this.cache.del(cacheKey);
  if (!entry || entry.expiresAt < Date.now()) {
    throw new NotFoundError('INVALID_LINK_CODE');
  }
  const user = await db.User.findOne({
    where: { id: entry.userId },
    attributes: ['id', 'selector', 'firstname', 'language'],
  });
  if (user === null) {
    throw new NotFoundError('INVALID_LINK_CODE');
  }
  await this.variable.setValue(
    CONTACT_VARIABLE,
    JSON.stringify({
      contact_id: contactId,
      contact_name: contactName || null,
      linked_at: new Date().toISOString(),
    }),
    service.id,
    user.id,
  );
  return {
    user: {
      selector: user.selector,
      first_name: user.firstname,
      language: user.language,
    },
  };
}

module.exports = {
  linkContact,
};
